"""Personalization layer for the Balkan.works consumer shell."""

from __future__ import annotations

from superapp_v2 import render_superapp_page as render_v2


def render_superapp_page(language: str = "SR", initial_tab: str = "home", initial_module: str = "") -> str:
    page = render_v2(language, initial_tab, initial_module)
    page = page.replace("</style>", """.profile-addons{margin-top:14px}.module-pills{display:flex;flex-wrap:wrap;gap:8px;margin-top:9px}.module-pill{border:1px solid var(--line);background:var(--mint);color:#18704f;border-radius:99px;padding:7px 9px;font-size:12px;font-weight:850}.module-toggle{width:100%;margin-top:9px;border:1px solid var(--line);background:#fff;color:var(--pine);padding:11px;border-radius:10px;text-align:left;font-weight:800}.module-toggle.active{background:var(--mint);border-color:#b8d9c6}.verification{display:flex;gap:7px;flex-wrap:wrap;margin-top:8px}.verification span{font-size:12px;border-radius:99px;padding:6px 8px;background:#fff1e9;color:#9b4b2c}.verification span.ok{background:var(--mint);color:#18704f}</style>""", 1)
    addon = '''<section class="profile-addons" id="profile-addons"><div class="rows"><div class="row"><div><b>Balkan ID</b><br><span id="id-status">Jedan nalog za ceo ekosistem</span></div><strong id="id-role">—</strong></div><div class="row"><div><b>Poeni</b><br><span>Balkan Rewards saldo</span></div><strong id="profile-points">—</strong></div><div class="row"><div><b>Verifikacije</b><br><span id="verification-summary">Proveravamo status</span><div class="verification" id="verification-list"></div></div></div><div class="row"><div><b>Aktivirani moduli</b><br><span>Samo oni ulaze u tvoj Home.</span><div class="module-pills" id="active-module-pills"></div></div></div><div class="row"><div><b>Uredi module</b><br><span>Uključi samo ono što želiš da pratiš.</span><div id="module-controls"></div></div></div></div></section>'''
    page = page.replace('</div></section>\n</main></div><nav class="bottom">', '</div>' + addon + '</section>\n</main></div><nav class="bottom">', 1)
    script = r'''<script>
const moduleKeyByName={"Save Food":"food","Deals":"deals","Services":"services","Jobs":"jobs","Business":"business","Money":"money","Auto":"auto","Health":"health","Tickets":"tickets","Balkan Local":"local"};
function escProfile(v){return String(v??'').replace(/[&<>"']/g,x=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[x]));}
function filterHomeModules(active){const keys=new Set(active.map(x=>x.key));const cards=[...document.querySelectorAll('.feature')];cards.forEach(card=>{const key=moduleKeyByName[card.querySelector('strong')?.textContent];if(key)card.style.display=keys.has(key)?'flex':'none'});const grid=document.querySelector('.feature-grid');if(grid&&!keys.size){grid.innerHTML='<div class="empty" style="grid-column:1/-1">Još nemaš aktivirane module. Otvori Profile → Uredi module i izaberi šta želiš na svom Home ekranu.</div>';}}
async function loadModulesForHome(){if(!token())return;try{const data=await api('/api/super-app/modules');filterHomeModules(data.active_modules||[])}catch(e){}}
async function moduleToggle(key,isActive){try{await api('/api/super-app/modules',{method:'PUT',headers:{'content-type':'application/json'},body:JSON.stringify({module_key:key,is_active:isActive})});loadProfileCenter();loadModulesForHome()}catch(e){const node=document.getElementById('module-controls');if(node)node.innerHTML='<p>'+escProfile(e.message)+'</p>';}}
async function loadProfileCenter(){if(!token())return;try{const d=await api('/api/super-app/profile');document.getElementById('profile-name').textContent=d.balkan_id.display_name;document.getElementById('profile-subtitle').textContent=d.balkan_id.email;document.getElementById('avatar').textContent=(d.balkan_id.display_name||'B')[0].toUpperCase();document.getElementById('profile-wallet').textContent=money(d.wallet.balance,d.wallet.currency);document.getElementById('id-role').textContent=d.balkan_id.role;document.getElementById('id-status').textContent=d.wallet.status==='provider_not_connected'?'Balkan ID je aktivan · Wallet provajder uskoro': 'Balkan ID je aktivan';document.getElementById('profile-points').textContent=d.rewards.points+' poena';const verified=d.verifications.filter(x=>x.verified);document.getElementById('verification-summary').textContent=verified.length+' / '+d.verifications.length+' potvrđeno';document.getElementById('verification-list').innerHTML=d.verifications.map(x=>'<span class="'+(x.verified?'ok':'')+'">'+(x.verified?'✓ ':'○ ')+escProfile(x.label)+'</span>').join('');document.getElementById('active-module-pills').innerHTML=d.active_modules.length?d.active_modules.map(x=>'<span class="module-pill">'+escProfile(x.name)+'</span>').join(''):'<span>Još nema aktiviranih modula.</span>';const active=new Set(d.active_modules.map(x=>x.key));const controls=["food","deals","services","jobs","business","money","auto","health","tickets","local"].map(key=>{const meta=(d.active_modules.find(x=>x.key===key)||{key:key,name:Object.entries(moduleKeyByName).find(([,v])=>v===key)?.[0]||key});const on=active.has(key);return '<button class="module-toggle '+(on?'active':'')+'" data-module-toggle="'+key+'">'+(on?'✓ ':'＋ ')+escProfile(meta.name)+'</button>'}).join('');document.getElementById('module-controls').innerHTML=controls;document.querySelectorAll('[data-module-toggle]').forEach(x=>x.onclick=()=>moduleToggle(x.dataset.moduleToggle,!active.has(x.dataset.moduleToggle)));filterHomeModules(d.active_modules)}catch(e){document.getElementById('profile-subtitle').textContent=e.message}}
document.querySelectorAll('[data-view="profile"]').forEach(x=>x.addEventListener('click',()=>setTimeout(loadProfileCenter,0)));if(token()){loadModulesForHome();if(initial==='profile')setTimeout(loadProfileCenter,0)}
</script>'''
    return page.replace("</body>", script + "</body>", 1)
